    # === 4-STROKE ENGINE CYCLE ===
    {"id": "AS001", "section": "Auto and Shop Information", "topic": "Engine Cycles", "question_text": "In what order do the four strokes of a gasoline engine occur?", "options": ["Compression, Intake, Power, Exhaust", "Intake, Compression, Power, Exhaust", "Power, Intake, Compression, Exhaust", "Intake, Power, Compression, Exhaust"], "correct_index": 1, "difficulty": 1, "explanation": "The four strokes in order: (1) Intake — piston moves down, drawing in air-fuel mixture; (2) Compression — piston moves up, compressing mixture; (3) Power — spark ignites mixture, piston forced down; (4) Exhaust — piston moves up, pushing out burned gases.", "test_types": ["ASVAB"]},
    {"id": "AS002", "section": "Auto and Shop Information", "topic": "Engine Cycles", "question_text": "During which stroke of a 4-stroke engine does combustion (burning of fuel) occur?", "options": ["Intake stroke", "Compression stroke", "Power stroke", "Exhaust stroke"], "correct_index": 2, "difficulty": 1, "explanation": "The power stroke: the compressed air-fuel mixture is ignited by the spark plug, causing rapid expansion that drives the piston down, converting chemical energy to mechanical motion.", "test_types": ["ASVAB"]},
    {"id": "AS003", "section": "Auto and Shop Information", "topic": "Engine Cycles", "question_text": "During the compression stroke, what does the piston do?", "options": ["Moves down, drawing in fuel mixture", "Moves up, compressing the air-fuel mixture", "Moves down as combustion occurs", "Moves up, pushing out exhaust gases"], "correct_index": 1, "difficulty": 1, "explanation": "During the compression stroke, both intake and exhaust valves are closed, and the piston moves up, compressing the air-fuel mixture. Compression increases temperature and makes combustion more efficient and powerful.", "test_types": ["ASVAB"]},
    {"id": "AS004", "section": "Auto and Shop Information", "topic": "Engine Cycles", "question_text": "A diesel engine differs from a gasoline engine in that a diesel engine:", "options": ["Uses spark plugs to ignite fuel", "Has only two strokes", "Ignites fuel by compression alone (no spark plugs)", "Runs cooler than gasoline engines"], "correct_index": 2, "difficulty": 2, "explanation": "Diesel engines use very high compression ratios (around 20:1 vs. 10:1 for gasoline) to heat the air so much that diesel fuel ignites spontaneously. No spark plugs are needed.", "test_types": ["ASVAB"]},

    # === ENGINE COMPONENTS ===
    {"id": "AS005", "section": "Auto and Shop Information", "topic": "Engine Components", "question_text": "What is the function of the crankshaft?", "options": ["Opens and closes the valves", "Converts the up-down motion of pistons into rotational motion", "Pumps oil throughout the engine", "Controls ignition timing"], "correct_index": 1, "difficulty": 1, "explanation": "The crankshaft converts the reciprocating (up-down) motion of the pistons into rotational motion that drives the transmission and wheels. It is one of the most critical engine components.", "test_types": ["ASVAB"]},
    {"id": "AS006", "section": "Auto and Shop Information", "topic": "Engine Components", "question_text": "The camshaft controls:", "options": ["Engine speed", "Opening and closing of intake and exhaust valves", "Fuel injection timing only", "Crankshaft rotation speed"], "correct_index": 1, "difficulty": 1, "explanation": "The camshaft's lobes (cams) push on the valve train to open and close the intake and exhaust valves at precisely the right times in the engine cycle. It is driven by the crankshaft via a timing chain or belt.", "test_types": ["ASVAB"]},
    {"id": "AS007", "section": "Auto and Shop Information", "topic": "Engine Components", "question_text": "What is the purpose of the head gasket?", "options": ["To lubricate the pistons", "To seal the joint between the engine block and cylinder head", "To control coolant temperature", "To connect the crankshaft to the camshaft"], "correct_index": 1, "difficulty": 2, "explanation": "The head gasket seals the mating surface between the engine block and cylinder head. It must seal combustion pressure, coolant passages, and oil passages. A blown head gasket allows coolant and/or oil to leak into combustion chambers.", "test_types": ["ASVAB"]},
    {"id": "AS008", "section": "Auto and Shop Information", "topic": "Engine Components", "question_text": "The spark plug's purpose is to:", "options": ["Regulate fuel flow", "Create a spark to ignite the compressed air-fuel mixture", "Measure engine temperature", "Release exhaust gases"], "correct_index": 1, "difficulty": 1, "explanation": "The spark plug fires an electrical spark at precisely the right moment to ignite the compressed air-fuel mixture during the power stroke. It screws into the cylinder head above each combustion chamber.", "test_types": ["ASVAB"]},
    {"id": "AS009", "section": "Auto and Shop Information", "topic": "Engine Components", "question_text": "Pistons move inside:", "options": ["The crankcase", "The cylinders", "The exhaust manifold", "The intake manifold"], "correct_index": 1, "difficulty": 1, "explanation": "Pistons move up and down inside the cylinders (cylindrical bores in the engine block). Piston rings on the piston seal against the cylinder walls to contain combustion pressure and control oil.", "test_types": ["ASVAB"]},

    # === COOLING SYSTEM ===
    {"id": "AS010", "section": "Auto and Shop Information", "topic": "Cooling System", "question_text": "What is the primary purpose of the radiator?", "options": ["Store coolant for the engine", "Cool the hot coolant by passing it through air-cooled fins", "Pressurize the cooling system", "Mix coolant with oil for lubrication"], "correct_index": 1, "difficulty": 1, "explanation": "The radiator is a heat exchanger — hot coolant from the engine flows through its fins, and air passing over the fins (from driving or the cooling fan) removes heat before the coolant returns to the engine.", "test_types": ["ASVAB"]},
    {"id": "AS011", "section": "Auto and Shop Information", "topic": "Cooling System", "question_text": "What does the thermostat regulate in an engine's cooling system?", "options": ["The amount of coolant in the system", "The coolant flow to maintain optimal engine operating temperature", "The radiator fan speed", "The pressure in the cooling system"], "correct_index": 1, "difficulty": 2, "explanation": "The thermostat is a temperature-controlled valve. It stays closed when the engine is cold (keeping coolant in the engine to warm up faster) and opens when the engine reaches operating temperature (allowing coolant to flow to the radiator for cooling).", "test_types": ["ASVAB"]},
    {"id": "AS012", "section": "Auto and Shop Information", "topic": "Cooling System", "question_text": "Antifreeze (coolant) does all of the following EXCEPT:", "options": ["Lower the freezing point of coolant", "Raise the boiling point of coolant", "Prevent corrosion in the cooling system", "Lubricate the pistons"], "correct_index": 3, "difficulty": 2, "explanation": "Antifreeze (ethylene glycol + water) prevents freezing in winter, raises the boiling point to prevent overheating, and contains corrosion inhibitors. Engine oil lubricates pistons, not coolant.", "test_types": ["ASVAB"]},
    {"id": "AS013", "section": "Auto and Shop Information", "topic": "Cooling System", "question_text": "The water pump in a cooling system:", "options": ["Stores excess coolant", "Circulates coolant through the engine and radiator", "Regulates coolant temperature", "Removes air bubbles from the system"], "correct_index": 1, "difficulty": 1, "explanation": "The water pump is driven by the engine (via belt or chain) and continuously circulates coolant through the engine block, cylinder head, and radiator. A failing water pump causes overheating.", "test_types": ["ASVAB"]},

    # === LUBRICATION SYSTEM ===
    {"id": "AS014", "section": "Auto and Shop Information", "topic": "Lubrication", "question_text": "Engine oil serves which of the following functions?", "options": ["Only lubrication of moving parts", "Lubrication, cooling, cleaning, and sealing", "Only cooling of the engine", "Only sealing piston rings"], "correct_index": 1, "difficulty": 2, "explanation": "Engine oil lubricates moving parts (reduces friction), cools components that coolant can't reach, cleans by carrying debris to the oil filter, and helps seal between piston rings and cylinder walls.", "test_types": ["ASVAB"]},
    {"id": "AS015", "section": "Auto and Shop Information", "topic": "Lubrication", "question_text": "Low engine oil pressure is dangerous because:", "options": ["It increases fuel consumption", "It causes the engine to overheat through the cooling system", "Moving parts are not adequately lubricated, causing rapid wear and damage", "The battery loses charge faster"], "correct_index": 2, "difficulty": 2, "explanation": "Low oil pressure means oil is not being forced to lubrication points fast enough. Metal surfaces contact metal directly, causing extreme wear, heat, and potentially catastrophic engine failure (seized engine).", "test_types": ["ASVAB"]},
    {"id": "AS016", "section": "Auto and Shop Information", "topic": "Lubrication", "question_text": "What is the function of the oil filter?", "options": ["Cool the engine oil", "Remove contaminants (dirt, metal particles) from the oil", "Measure oil pressure", "Regulate the amount of oil used"], "correct_index": 1, "difficulty": 1, "explanation": "The oil filter removes contaminants — metal particles, dirt, carbon deposits — from the engine oil as it circulates. Filters are changed with oil changes to prevent buildup of harmful particles.", "test_types": ["ASVAB"]},

    # === FUEL SYSTEM ===
