    {"id": "AS018", "section": "Auto and Shop Information", "topic": "Fuel System", "question_text": "How does fuel injection differ from a carburetor?", "options": ["Fuel injection uses more fuel", "Fuel injection uses computer control for precise fuel delivery; carburetors use air flow venturi effect", "Carburetors are found only in diesel engines", "Fuel injection works only at high speeds"], "correct_index": 1, "difficulty": 2, "explanation": "Carburetors use the venturi effect (air flow creating suction) to draw fuel from a bowl — mechanical and simple but imprecise. Fuel injection uses electronic sensors and an ECU to deliver exactly the right fuel amount.", "test_types": ["ASVAB"]},
    {"id": "AS019", "section": "Auto and Shop Information", "topic": "Fuel System", "question_text": "The fuel filter prevents:", "options": ["Fuel from evaporating", "Contamination (dirt, rust particles) from reaching the injectors or carburetor", "The fuel pump from over-pressurizing", "Fuel from mixing with oil"], "correct_index": 1, "difficulty": 1, "explanation": "The fuel filter catches contaminants before they reach the fuel injectors or carburetor. Clogged injectors cause poor performance. Fuel filters should be replaced periodically.", "test_types": ["ASVAB"]},

