    {"id": "AS021", "section": "Auto and Shop Information", "topic": "Ignition System", "question_text": "The starter motor's purpose is to:", "options": ["Keep the engine running after starting", "Crank the engine to begin the combustion cycle", "Generate electricity for the battery", "Control ignition timing"], "correct_index": 1, "difficulty": 1, "explanation": "The starter motor is an electric motor powered by the battery. It cranks (turns) the engine fast enough to start the combustion cycle. Once the engine runs, the starter disengages.", "test_types": ["ASVAB"]},
