    {"id": "AS043", "section": "Auto and Shop Information", "topic": "Tools", "question_text": "Which wrench is best suited for tightening bolts in a confined space where a swing arc is limited?", "options": ["Open-end wrench", "Combination wrench", "Ratchet and socket", "Adjustable wrench"], "correct_index": 2, "difficulty": 2, "explanation": "A ratchet and socket allows tightening with a short back-and-forth motion — you don't need to reposition the wrench after each stroke. This is ideal in confined spaces. Open-end and adjustable wrenches require more swing arc.", "test_types": ["ASVAB"]},
