    {"id": "AS045", "section": "Auto and Shop Information", "topic": "Tools", "question_text": "A hacksaw is used to:", "options": ["Shape metal by filing", "Cut metal, plastic, or pipe", "Drive screws into metal", "Measure metal thickness"], "correct_index": 1, "difficulty": 1, "explanation": "A hacksaw cuts through metal, plastic, conduit, and pipe using a fine-toothed replaceable blade. The teeth point forward, cutting on the push stroke. Different blade tooth counts suit different materials.", "test_types": ["ASVAB"]},
    {"id": "AS046", "section": "Auto and Shop Information", "topic": "Tools", "question_text": "A C-clamp is used to:", "options": ["Cut metal in a curved line", "Hold workpieces firmly in place while cutting, welding, or gluing", "Measure the inside diameter of a cylinder", "Remove seized bolts"], "correct_index": 1, "difficulty": 1, "explanation": "A C-clamp holds materials together or secures them to a workbench. The C-shaped frame and threaded screw apply clamping force. Common in woodworking and metalworking.", "test_types": ["ASVAB"]},
